function priceQuoteStep(step: QuoteStep): { premium: number } {
  const policyBase = step.items.reduce(
    (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
    0,
  );
  const curseSurcharge = step.items.reduce(
    (sum, item) =>
      sum + (item.cursed ? (BASE_PREMIUM[item.type] ?? 0) * 0.5 : 0),
    0,
  );
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(
    policyBase + curseSurcharge + firstInsurance + PROCESSING_FEE,
  );
  return { premium };
}
